bool cDatabaseManager::Write(Simulator::ISerializerStream* stream)
{
	if (!IsSpaceGame() || readFailedPermanently)
	{
		return true;
	}
	if (!dependenciesInjected)
	{
		ModAPI::Log("Error: attempted to write persisted objects before dependencies were injected.");
		return false;
	}
	if (persistedObjectDB == nullptr)
	{
		if (!InitializeDB())
		{
			ModAPI::Log("Error initializing db.");
			return false;
		}
	}
	if (!persistedObjectDB->Open(IO::AccessFlags::Write, IO::CD::OpenAlways))
	{
		ModAPI::Log("Error opening db for Write.");
		return false;
	}
	auto it = persistedObjects.begin();
	while (it != persistedObjects.end())
	{
		cPersistedObject* persistedObject = it->get();
		if (persistedObject == nullptr)
		{
			it = persistedObjects.erase(it);
			continue;
		}
		ISerializerWriteStream* writeStream = nullptr;
		ResourceKey key = GetResourceKey(persistedObject);
		if (persistedObject->Valid())
		{
			if (persistedObject->GetInstanceID() == 0 && persistedObject->GetNounID() != cPersistenceState::NOUN_ID)
			{
				ModAPI::Log("Error: Object with type %u and instanceID = 0", key.typeID);
				continue;
			}
			if (!persistedObjectDB->OpenWriteStream(key, &writeStream, true))
			{
				ModAPI::Log("Error opening write stream for key %u %u %u.", key.instanceID, key.groupID, key.typeID);
				it++;
				continue;
			}
			if (!persistedObject->Write(writeStream))
			{
				ModAPI::Log("Error writing key %u %u %u.",
					key.instanceID, key.groupID, key.typeID);
			}
			persistedObjectDB->CloseWriteStream(writeStream);
			it++;
		}
		else
		{
			if (persistenceState.get() == it->get())
			{
				ModAPI::Log("Error: persistenceState became invalid.");
				persistenceState.reset();
			}
			persistedObjectDB->DeleteRecord(key);
			it = persistedObjects.erase(it);
		}
	}
	if (!persistedObjectDB->Flush())
	{
		ModAPI::Log("Error flushing db");
	}
	if (!persistedObjectDB->Close())
	{
		ModAPI::Log("Error closing db");
		return false;
	}
	return Simulator::ClassSerializer(this, ATTRIBUTES).Write(stream);
}
bool cDatabaseManager::Read(Simulator::ISerializerStream* stream)
{
	if (!readDB && !readFailedPermanently)
	{
		ReadDB();
	}
	return readDB && Simulator::ClassSerializer(this, ATTRIBUTES).Read(stream);
}

